sql:
SELECT 
    (SELECT COUNT(panel_id) FROM panels) as total_panels,
    (SELECT AVG(metric_value) FROM panel_performance_metrics WHERE metric_name = 'load_time') as average_load_time;

SELECT LTRIM(custom_css) AS trimmed_custom_css, header, disabled
FROM panels
WHERE disabled = 0 AND custom_css NOT LIKE ' %';

SELECT panel_id, version_number
FROM panel_versions
WHERE version_id = 0;

SELECT COUNT(DISTINCT panel_id) AS total_panels
FROM panel_usage_logs
WHERE usage_date = '2023-05-02';

SELECT 
  (SELECT AVG(duration) FROM panel_usage_logs) AS average_usage_duration,
  (SELECT MAX(metric_value) FROM panel_performance_metrics WHERE metric_name = 'render_time') AS max_render_time;

SELECT panel_id, MAX(version_number) AS highest_version
  FROM panel_versions
  GROUP BY panel_id;

external_knowledge:
- The 'latest version of each panel' refers to the version with the highest version number; 
- 'interacts with the most' means the panel with the highest duration in the panel usage logs for each user; 
- 'layout dependencies' refers to the dependent panels that have a dependency type of 'layout'.

